   214→
   215→### Epic: Universal Recruitment Fabric (URF)
   216→**Story Points: 7**
   217→
   218→#### URF-001: Implement @psyforge/recruit-bridge for Prolific
   219→**Points: 4 | Priority: High**
   220→
   221→**Description:** Build the first recruitment provider integration with Prolific's API.
   222→
   223→**Technical Requirements:**
   224→- Prolific API v1 integration for study creation and management
   225→- Participant prescreening attribute mapping
   226→- Automatic study URL generation and participant routing
   227→- Compensation calculation and bonus payment support
   228→- Error handling and retry logic for API failures
   229→
   230→**Acceptance Criteria:**
   231→- [ ] Studies created on Prolific automatically from ForgeScript config
   232→- [ ] Prescreening attributes correctly mapped and validated
   233→- [ ] Participant routing URLs generated with proper parameters
   234→- [ ] Compensation and bonus payments processed automatically
   235→- [ ] API errors handled gracefully with user-friendly messages
   236→- [ ] Integration tested with Prolific sandbox environment
   237→
   238→**Prolific Integration Implementation:**
   239→```typescript
   240→// @psyforge/recruit-bridge
   241→export interface RecruitmentProvider {
   242→  readonly name: string;
   243→  
   244→  // Create study on platform
   245→  createStudy(config: StudyConfig): Promise<ExternalStudyId>;
   246→  
   247→  // Update study parameters
   248→  updateStudy(externalId: ExternalStudyId, config: Partial<StudyConfig>): Promise<void>;
   249→  
   250→  // Publish study to start recruitment
   251→  publishStudy(externalId: ExternalStudyId): Promise<void>;
   252→  
   253→  // Handle study completion and payments
   254→  completeStudy(externalId: ExternalStudyId): Promise<void>;
   255→  
   256→  // Process individual participant completion
   257→  approveSubmission(externalId: ExternalStudyId, participantId: string): Promise<void>;
   258→  
   259→  // Send bonus payments
   260→  bonusPayment(externalId: ExternalStudyId, participantId: string, amount: number): Promise<void>;
   261→}
   262→
   263→export class ProlificProvider implements RecruitmentProvider {
   264→  readonly name = 'prolific';
   265→  
   266→  private apiClient: ProlificAPIClient;
   267→  
   268→  constructor(apiKey: string, sandbox = false) {
   269→    this.apiClient = new ProlificAPIClient(apiKey, sandbox);
   270→  }
   271→  
   272→  async createStudy(config: StudyConfig): Promise<string> {
   273→    // Map ForgeScript recruitment config to Prolific study format
   274→    const prolificStudy = {
   275→      name: config.name,
   276→      description: config.description,
   277→      external_study_url: config.studyUrl,
   278→      prolific_id_option: 'url_parameters', // Pass PROLIFIC_PID in URL
   279→      completion_code: config.completionCode,
   280→      completion_option: 'redirect',
   281→      total_available_places: config.targetParticipants,
   282→      reward: config.compensation.base, // In pence for GBP
   283→      estimated_completion_time: config.estimatedDuration,
   284→      
   285→      // Map screening criteria
   286→      eligibility_requirements: this.mapScreeningCriteria(config.criteria)
   287→    };
   288→    
   289→    const response = await this.apiClient.post('/studies/', prolificStudy);
   290→    return response.id;
   291→  }
   292→  
   293→  private mapScreeningCriteria(criteria: ScreeningCriteria): ProlificEligibilityRequirement[] {
   294→    const requirements: ProlificEligibilityRequirement[] = [];
   295→    
   296→    // Age requirements
   297→    if (criteria.age) {
   298→      requirements.push({
   299→        _cls: 'web.eligibility.models.AgeRangeEligibilityRequirement',
   300→        min_age: criteria.age.min,
   301→        max_age: criteria.age.max
   302→      });
   303→    }
   304→    
   305→    // Language requirements
   306→    if (criteria.language) {
   307→      requirements.push({
   308→        _cls: 'web.eligibility.models.LanguageEligibilityRequirement',
   309→        language: this.mapLanguageCode(criteria.language)
   310→      });
   311→    }
   312→    
   313→    // Custom screening questions
   314→    if (criteria.customScreening) {
   315→      criteria.customScreening.forEach(screen => {
   316→        requirements.push({
   317→          _cls: 'web.eligibility.models.CustomEligibilityRequirement',
   318→          question: screen.question,
   319→          accepted_answers: screen.acceptedAnswers
   320→        });
   321→      });
   322→    }
   323→    
   324→    return requirements;
   325→  }
   326→}
   327→
   328→// Provider registry and factory
   329→export class RecruitmentProviderRegistry {
   330→  private providers = new Map<string, () => RecruitmentProvider>();
   331→  
   332→  register(name: string, factory: () => RecruitmentProvider): void {
   333→    this.providers.set(name, factory);
   334→  }
   335→  
