    40→  };
    41→  private performanceMetrics: PerformanceMetrics = {
    42→    fps: 0,
    43→    frameDrops: 0,
    44→    memoryUsage: this.memoryMetrics,
    45→    cpuUsage: 0,
    46→    simulationSpeed: 1
    47→  };
