    51→  constructor(config: HeadlessConfig) {
    52→    this.config = config;
    53→    // this.clock = new PrecisionClock();
    54→    
    55→    // Initialize deterministic random number generator
    56→    this.rng = this.createRNG(config.randomSeed);
    57→    
    58→    // Initialize participants
    59→    this.initializeParticipants();
    60→    
    61→    // Initialize virtual devices
