    63→    
    64→    // Set memory budget if specified
    65→    if (config.memoryBudget) {
    66→      this.memoryMetrics.wasmMemoryLimit = config.memoryBudget;
    67→    }
    68→  }
    69→
    70→  /**
    71→   * Run complete experiment simulation
    72→   */
    73→  async simulate(): Promise<SimulationResults> {
    74→    this.realStartTime = performance.now();
    75→    
    76→    // Calculate total experiment duration
    77→    const totalDuration = this.calculateExperimentDuration();
    78→    
    79→    // Run simulation loop
    80→    while (this.virtualTime < totalDuration) {
    81→      await this.simulateFrame();
    82→      
    83→      // Check memory usage
    84→      if (this.memoryMetrics.wasmMemoryUsed > this.memoryMetrics.wasmMemoryLimit) {
    85→        throw new Error(`Memory budget exceeded: ${this.memoryMetrics.wasmMemoryUsed} > ${this.memoryMetrics.wasmMemoryLimit}`);
    86→      }
    87→    }
    88→    
    89→    // Compile results
    90→    return this.compileResults();
    91→  }
    92→
    93→  /**
    94→   * Run simulation until specific time point
    95→   */
    96→  async simulateUntil(targetTime: number): Promise<SimulationState> {
    97→    while (this.virtualTime < targetTime) {
    98→      await this.simulateFrame();
    99→    }
   100→    
   101→    return this.getCurrentState();
   102→  }
   103→
   104→  /**
   105→   * Simulate a single frame
   106→   */
   107→  private async simulateFrame(): Promise<void> {
   108→    const frameStart = performance.now();
   109→    
   110→    // Calculate virtual time increment based on speed multiplier
   111→    const virtualIncrement = (16.67 / 1000) * this.config.speedMultiplier; // 60fps base
   112→    this.virtualTime += virtualIncrement;
   113→    
   114→    // Process experiment logic for current time
   115→    await this.processExperimentFrame();
   116→    
   117→    // Update performance metrics
   118→    const frameEnd = performance.now();
   119→    const frameDuration = frameEnd - frameStart;
   120→    this.updatePerformanceMetrics(frameDuration);
   121→    
   122→    // Yield to event loop periodically for non-blocking simulation
   123→    if (Math.random() < 0.01) { // 1% chance
   124→      await new Promise(resolve => setImmediate(resolve));
   125→    }
   126→  }
   127→
   128→  /**
   129→   * Process experiment logic for current frame
   130→   */
   131→  private async processExperimentFrame(): Promise<void> {
   132→    // This would integrate with the ForgeScript runtime
   133→    // For now, simulate basic experiment flow
   134→    
   135→    for (const [participantId, state] of this.participants) {
   136→      // Check if participant should respond at this time
   137→      const shouldRespond = this.checkResponseWindow(state);
   138→      
   139→      if (shouldRespond) {
   140→        const response = this.generateResponse(state);
   141→        this.recordResponse(participantId, response);
   142→        this.updateParticipantState(state, response);
   143→      }
   144→    }
   145→  }
   146→
   147→  /**
   148→   * Generate participant response based on cognitive model
   149→   */
   150→  private generateResponse(participant: ParticipantState): TrialResult {
   151→    // Get current stimulus from experiment
   152→    const stimulus = this.getCurrentStimulus();
   153→    
   154→    // Calculate reaction time using cognitive model
   155→    const difficulty = this.calculateDifficulty(stimulus);
   156→    const rt = this.config.cognitiveModel.reactionTime(stimulus, difficulty);
   157→    
   158→    // Add noise and fatigue effects
   159→    const noisyRT = rt * (1 + (this.rng() - 0.5) * 0.1); // ±5% noise
   160→    const finalRT = noisyRT * (1 + participant.fatigue * 0.2); // Up to 20% slower when fatigued
   161→    
   162→    // Determine accuracy
   163→    const correct = this.config.cognitiveModel.accuracy(stimulus, participant.fatigue);
   164→    
   165→    // Determine response key
   166→    const responseKey = this.selectResponseKey(stimulus, correct);
   167→    
   168→    // Simulate device response
   169→    let deviceResponse: any = { key: responseKey };
   170→    let deviceLatency = 0;
   171→    
   172→    if (this.config.virtualDevices?.keyboard) {
   173→      const keyboard = this.virtualDevices.get('keyboard') as VirtualKeyboardDevice;
   174→      const keyPress = keyboard.simulateKeyPress(responseKey, this.virtualTime + finalRT);
   175→      deviceResponse = { key: keyPress.key };
   176→      deviceLatency = keyPress.latency;
   177→    }
   178→    
   179→    return {
   180→      trialNumber: participant.trialsCompleted + 1,
   181→      condition: stimulus.condition || 'default',
   182→      stimulus,
   183→      response: deviceResponse,
   184→      rt: Math.round(finalRT + deviceLatency),
   185→      correct,
   186→      timestamp: this.virtualTime
   187→    };
   188→  }
   189→
   190→  /**
   191→   * Get current state of simulation
   192→   */
   193→  private getCurrentState(): SimulationState {
   194→    const participantStates = Array.from(this.participants.values());
   195→    const averageState = this.calculateAverageParticipantState(participantStates);
   196→    const currentStimulus = this.getCurrentStimulus();
   197→    
   198→    return {
   199→      virtualTime: this.virtualTime,
   200→      currentTime: this.virtualTime * 1000, // Convert to ms
   201→      phase: this.getCurrentPhase(),
   202→      activeStimuli: currentStimulus ? [currentStimulus] : [],
   203→      events: this.getSimulationEvents(),
   204→      currentEvent: this.getCurrentEvent(),
   205→      participantId: 'P001', // Average participant
   206→      trialNumber: averageState.trialsCompleted + 1,
   207→      totalTrials: this.calculateTotalTrials(),
   208→      blockNumber: Math.floor(averageState.trialsCompleted / 20) + 1,
   209→      totalBlocks: Math.ceil(this.calculateTotalTrials() / 20),
   210→      condition: this.getCurrentCondition(),
   211→      currentInstruction: this.getCurrentInstruction(),
   212→      lastResponse: this.getLastResponse(),
   213→      totalDuration: this.calculateExperimentDuration() * 1000, // Convert to ms
   214→      currentTrial: averageState.trialsCompleted,
   215→      currentBlock: Math.floor(averageState.trialsCompleted / 20),
   216→      stimulusOnScreen: currentStimulus,
   217→      participantState: averageState,
   218→      performanceMetrics: { ...this.performanceMetrics }
   219→    };
   220→  }
   221→
   222→  /**
   223→   * Compile final results
   224→   */
   225→  private compileResults(): SimulationResults {
   226→    const participants: ParticipantResults[] = [];
   227→    
   228→    for (const [participantId, trials] of this.results) {
   229→      const summary = this.calculateParticipantSummary(trials);
   230→      participants.push({
   231→        participantId,
   232→        trials,
   233→        summary
   234→      });
   235→    }
   236→    
   237→    const aggregateMetrics = this.calculateAggregateMetrics(participants);
   238→    const performanceReport = this.generatePerformanceReport();
   239→    const totalDuration = this.calculateExperimentDuration() * 1000; // Convert to ms
   240→    const wallClockTime = performance.now() - this.realStartTime;
   241→    
   242→    return {
   243→      participants,
   244→      aggregateMetrics,
   245→      performanceReport,
   246→      dataExport: this.exportData(participants),
   247→      totalDuration,
   248→      participantResults: participants,
   249→      performanceMetrics: {
   250→        simulationTime: totalDuration,
   251→        wallClockTime,
   252→        speedMultiplier: totalDuration / wallClockTime
   253→      }
   254→    };
   255→  }
   256→
   257→  /**
   258→   * Calculate participant summary statistics
   259→   */
   260→  private calculateParticipantSummary(trials: TrialResult[]): any {
   261→    const correctTrials = trials.filter(t => t.correct).length;
   262→    const rts = trials.map(t => t.rt);
   263→    
   264→    return {
   265→      totalTrials: trials.length,
   266→      correctTrials,
   267→      accuracy: correctTrials / trials.length,
   268→      meanRT: this.mean(rts),
   269→      sdRT: this.standardDeviation(rts),
   270→      medianRT: this.median(rts),
   271→      minRT: Math.min(...rts),
   272→      maxRT: Math.max(...rts)
   273→    };
   274→  }
   275→
   276→  /**
   277→   * Calculate aggregate metrics across participants
   278→   */
   279→  private calculateAggregateMetrics(participants: ParticipantResults[]): AggregateMetrics {
   280→    const allTrials = participants.flatMap(p => p.trials);
   281→    const conditions = new Set(allTrials.map(t => t.condition));
   282→    
   283→    const conditionEffects: Record<string, any> = {};
   284→    for (const condition of conditions) {
   285→      const conditionTrials = allTrials.filter(t => t.condition === condition);
   286→      conditionEffects[condition] = {
   287→        accuracy: conditionTrials.filter(t => t.correct).length / conditionTrials.length,
   288→        meanRT: this.mean(conditionTrials.map(t => t.rt)),
   289→        sdRT: this.standardDeviation(conditionTrials.map(t => t.rt)),
   290→        n: conditionTrials.length
   291→      };
   292→    }
   293→    
   294→    return {
   295→      overallAccuracy: allTrials.filter(t => t.correct).length / allTrials.length,
   296→      overallMeanRT: this.mean(allTrials.map(t => t.rt)),
   297→      conditionEffects,
   298→      learningCurve: this.calculateLearningCurve(allTrials),
   299→      fatigueEffects: this.calculateFatigueEffects(participants)
   300→    };
   301→  }
   302→
   303→  /**
   304→   * Generate performance report
   305→   */
   306→  private generatePerformanceReport(): PerformanceReport {
   307→    const realDuration = performance.now() - this.realStartTime;
   308→    const virtualDuration = this.virtualTime * 1000; // Convert to ms
   309→    
   310→    return {
   311→      totalSimulationTime: realDuration,
   312→      virtualTimeElapsed: virtualDuration,
   313→      speedupFactor: virtualDuration / realDuration,
   314→      memoryPeakUsage: this.memoryMetrics.wasmMemoryUsed,
   315→      averageFPS: this.performanceMetrics.fps,
   316→      determinismCheck: true // Would verify reproducibility with same seed
   317→    };
   318→  }
   319→
   320→  /**
   321→   * Initialize participant states
   322→   */
   323→  private initializeParticipants(): void {
   324→    for (let i = 0; i < this.config.participants; i++) {
   325→      const id = `P${String(i + 1).padStart(3, '0')}`;
   326→      this.participants.set(id, {
   327→        id,
   328→        fatigue: 0,
   329→        accuracy: 1,
   330→        meanRT: 400,
   331→        trialsCompleted: 0,
   332→        errors: 0,
   333→        learningCoefficient: 1
   334→      });
   335→      this.results.set(id, []);
   336→    }
   337→  }
   338→
   339→  /**
   340→   * Create deterministic random number generator
   341→   */
   342→  private createRNG(seed?: number): () => number {
   343→    let s = seed ?? Date.now();
   344→    return () => {
   345→      s = (s * 1664525 + 1013904223) % 4294967296;
   346→      return s / 4294967296;
   347→    };
   348→  }
   349→
   350→  /**
   351→   * Update performance metrics
   352→   */
   353→  private updatePerformanceMetrics(frameDuration: number): void {
   354→    this.performanceMetrics.fps = 1000 / frameDuration;
   355→    this.performanceMetrics.simulationSpeed = this.config.speedMultiplier;
   356→    
   357→    // Update memory metrics (would use actual WASM memory in production)
   358→    if (typeof process !== 'undefined' && process.memoryUsage) {
   359→      const usage = process.memoryUsage();
   360→      this.memoryMetrics.heapUsed = usage.heapUsed;
   361→      this.memoryMetrics.heapTotal = usage.heapTotal;
   362→      this.memoryMetrics.wasmMemoryUsed = usage.heapUsed; // Placeholder
   363→    }
   364→  }
   365→
   366→  /**
   367→   * Get memory usage metrics
   368→   */
   369→  getMemoryUsage(): MemoryMetrics {
   370→    return { ...this.memoryMetrics };
   371→  }
   372→
   373→  // Helper methods
   374→  private mean(values: number[]): number {
   375→    return values.reduce((a, b) => a + b, 0) / values.length;
   376→  }
   377→
   378→  private standardDeviation(values: number[]): number {
   379→    const avg = this.mean(values);
   380→    const squareDiffs = values.map(value => Math.pow(value - avg, 2));
   381→    return Math.sqrt(this.mean(squareDiffs));
   382→  }
   383→
   384→  private median(values: number[]): number {
   385→    const sorted = [...values].sort((a, b) => a - b);
   386→    const mid = Math.floor(sorted.length / 2);
   387→    return sorted.length % 2 ? sorted[mid] : (sorted[mid - 1] + sorted[mid]) / 2;
   388→  }
   389→
   390→  // Placeholder methods that would integrate with ForgeScript runtime
   391→  private calculateExperimentDuration(): number {
   392→    // Would calculate from experiment structure
   393→    return 300; // 5 minutes default
   394→  }
   395→
   396→  private getCurrentStimulus(): any {
   397→    // Would get from experiment timeline
   398→    return { type: 'text', content: 'TEST', condition: 'congruent' };
   399→  }
   400→
   401→  private checkResponseWindow(participant: ParticipantState): boolean {
   402→    // Would check experiment timeline
   403→    return Math.random() < 0.01; // 1% chance per frame for testing
   404→  }
   405→
   406→  private calculateDifficulty(stimulus: any): number {
   407→    // Would calculate from stimulus properties
   408→    return stimulus.condition === 'incongruent' ? 0.8 : 0.2;
   409→  }
   410→
   411→  private selectResponseKey(stimulus: any, correct: boolean): string {
   412→    // Would determine based on stimulus and correctness
   413→    return correct ? 'ArrowLeft' : 'ArrowRight';
   414→  }
   415→
   416→  private recordResponse(participantId: string, response: TrialResult): void {
   417→    const trials = this.results.get(participantId) || [];
   418→    trials.push(response);
   419→    this.results.set(participantId, trials);
   420→  }
   421→
   422→  private updateParticipantState(state: ParticipantState, response: TrialResult): void {
   423→    state.trialsCompleted++;
   424→    if (!response.correct) state.errors++;
   425→    
   426→    // Update fatigue (increases over time)
   427→    state.fatigue = Math.min(1, state.fatigue + 0.001);
   428→    
   429→    // Update learning coefficient
   430→    const learningRate = this.config.cognitiveModel.learningCurve(
   431→      state.trialsCompleted,
   432→      response.condition
   433→    );
   434→    state.learningCoefficient *= learningRate;
   435→    
   436→    // Update running accuracy
   437→    state.accuracy = (state.trialsCompleted - state.errors) / state.trialsCompleted;
   438→  }
   439→
   440→  private calculateAverageParticipantState(states: ParticipantState[]): ParticipantState {
   441→    const avg = {
   442→      id: 'average',
   443→      fatigue: this.mean(states.map(s => s.fatigue)),
   444→      accuracy: this.mean(states.map(s => s.accuracy)),
   445→      meanRT: this.mean(states.map(s => s.meanRT)),
   446→      trialsCompleted: Math.round(this.mean(states.map(s => s.trialsCompleted))),
   447→      errors: Math.round(this.mean(states.map(s => s.errors))),
   448→      learningCoefficient: this.mean(states.map(s => s.learningCoefficient))
   449→    };
   450→    return avg;
   451→  }
   452→
   453→  private calculateLearningCurve(trials: TrialResult[]): number[] {
   454→    // Group trials by trial number and calculate accuracy
   455→    const maxTrial = Math.max(...trials.map(t => t.trialNumber));
   456→    const curve: number[] = [];
   457→    
   458→    for (let i = 1; i <= maxTrial; i++) {
   459→      const trialsAtN = trials.filter(t => t.trialNumber === i);
   460→      if (trialsAtN.length > 0) {
   461→        curve.push(trialsAtN.filter(t => t.correct).length / trialsAtN.length);
   462→      }
   463→    }
   464→    
   465→    return curve;
   466→  }
   467→
   468→  private calculateFatigueEffects(participants: ParticipantResults[]): number[] {
   469→    // Calculate RT increase over time as fatigue indicator
   470→    const effects: number[] = [];
   471→    const blockSize = 20;
   472→    
   473→    for (const participant of participants) {
   474→      const blocks = Math.floor(participant.trials.length / blockSize);
   475→      for (let i = 0; i < blocks; i++) {
   476→        const blockTrials = participant.trials.slice(i * blockSize, (i + 1) * blockSize);
   477→        const meanRT = this.mean(blockTrials.map(t => t.rt));
   478→        effects.push(meanRT);
   479→      }
   480→    }
   481→    
   482→    return effects;
   483→  }
   484→
   485→  private exportData(participants: ParticipantResults[]): any[] {
   486→    // Export in BIDS-compatible format
   487→    const data: any[] = [];
   488→    
   489→    for (const participant of participants) {
   490→      for (const trial of participant.trials) {
   491→        data.push({
   492→          participant_id: participant.participantId,
   493→          trial: trial.trialNumber,
