   495→          rt: trial.rt,
   496→          accuracy: trial.correct ? 1 : 0,
   497→          onset: trial.timestamp,
   498→          duration: trial.rt / 1000
   499→        });
   500→      }
   501→    }
   502→    
   503→    return data;
   504→  }
