   506→  /**
   507→   * Initialize virtual devices based on configuration
   508→   */
   509→  private initializeVirtualDevices(): void {
   510→    if (!this.config.virtualDevices) return;
   511→    
   512→    // Initialize keyboard device
   513→    if (this.config.virtualDevices.keyboard) {
