   581→  /**
   582→   * Get simulation events for timeline
   583→   */
   584→  private getSimulationEvents(): Array<{ type: string; time: number; description: string }> {
   585→    const events: Array<{ type: string; time: number; description: string }> = [];
   586→    
   587→    // Generate events based on trial structure
   588→    const trialDuration = 3000; // 3s per trial
   589→    const totalTrials = this.calculateTotalTrials();
   590→    
   591→    for (let i = 0; i < totalTrials; i++) {
   592→      const trialStart = i * trialDuration;
   593→      events.push({
