/**
 * @psyforge/ai-assistant
 * AI-powered experiment design assistant
 */

import OpenAI from 'openai';
import Anthropic from '@anthropic-ai/sdk';
import type {
  AIConfig,
  AIModel,
  DesignCommand,
  ExperimentContext,
  Suggestion,
  ValidationResult,
  DesignIntent
} from './types.js';
import { DesignCommandSchema } from './types.js';
import { CodeGenerator } from './CodeGenerator.js';
import { CodeValidator } from './CodeValidator.js';
import { SYSTEM_PROMPTS } from './prompts.js';

/**
 * Main AI assistant for experiment design
 */
export class AIDesignAssistant {
  private openai?: OpenAI;
  private anthropic?: Anthropic;
  private generator: CodeGenerator;
  private validator: CodeValidator;
  private config: AIConfig;

  constructor(config: AIConfig) {
    this.config = config;

    // Initialize the appropriate AI client
    if (config.model.startsWith('gpt')) {
      this.openai = new OpenAI({ apiKey: config.apiKey });
    } else if (config.model.startsWith('claude')) {
      this.anthropic = new Anthropic({ apiKey: config.apiKey });
    } else {
      throw new Error(`Unsupported AI model: ${config.model}`);
    }

    this.generator = new CodeGenerator();
    this.validator = new CodeValidator();
  }

  /**
   * Parse natural language command into structured format
   */
  async parseCommand(
    input: string,
    context: ExperimentContext
  ): Promise<DesignCommand> {
    const prompt = this.buildParsingPrompt(input, context);

    try {
      const response = await this.callAI(prompt, 'parsing');
      const parsed = JSON.parse(response);

      // Validate the parsed command
      const validated = DesignCommandSchema.parse({
        ...parsed,
        originalInput: input,
        context
      });

      return validated;
    } catch (error) {
      // Fallback to simple intent detection
      return this.fallbackParsing(input, context);
    }
  }

  /**
   * Generate ForgeScript code from a design command
   */
  async generateCode(command: DesignCommand): Promise<string> {
    return this.generator.generateFromCommand(command);
  }

  /**
   * Validate generated or user-provided code
   */
  async validateCode(code: string): Promise<ValidationResult> {
    return this.validator.validate(code);
  }

  /**
   * Suggest improvements for the current experiment
   */
  async suggestImprovements(
    experiment: any // CompiledExperiment
  ): Promise<Suggestion[]> {
    const prompt = this.buildSuggestionPrompt(experiment);

    try {
      const response = await this.callAI(prompt, 'suggestions');
      const suggestions = JSON.parse(response);

      return Array.isArray(suggestions) ? suggestions : [];
    } catch (error) {
      console.error('Failed to generate suggestions:', error);
      return [];
    }
  }

  /**
   * Get contextual command suggestions based on current state
   */
  async getCommandSuggestions(
    partialInput: string,
    context: ExperimentContext
  ): Promise<string[]> {
    const prompt = this.buildSuggestionPrompt(partialInput, context);

    try {
      const response = await this.callAI(prompt, 'autocomplete');
      const suggestions = JSON.parse(response);

      return Array.isArray(suggestions) ? suggestions.slice(0, 5) : [];
    } catch (error) {
      // Return static suggestions as fallback
      return this.getStaticSuggestions(partialInput);
    }
  }

  /**
   * Explain a concept or provide help
   */
  async explainConcept(concept: string): Promise<string> {
    const prompt = `Explain the following psychology experiment concept in simple terms: ${concept}`;

    try {
      return await this.callAI(prompt, 'explanation');
    } catch (error) {
      return `I couldn't generate an explanation for "${concept}". Please try rephrasing your question.`;
    }
  }

  /**
   * Call the appropriate AI service
   */
  private async callAI(prompt: string, type: string): Promise<string> {
    const systemPrompt = this.config.systemPrompt || SYSTEM_PROMPTS[type] || SYSTEM_PROMPTS.default;

    if (this.openai) {
      const response = await this.openai.chat.completions.create({
        model: this.config.model as string,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: prompt }
        ],
        temperature: this.config.temperature || 0.7,
        max_tokens: this.config.maxTokens || 1000,
        stream: false
      });

      return response.choices[0]?.message?.content || '';
    } else if (this.anthropic) {
      const response = await this.anthropic.messages.create({
        model: this.config.model as string,
        messages: [{ role: 'user', content: prompt }],
        system: systemPrompt,
        temperature: this.config.temperature || 0.7,
        max_tokens: this.config.maxTokens || 1000
      });

      return response.content[0]?.type === 'text' 
        ? response.content[0].text 
        : '';
    }

    throw new Error('No AI client configured');
  }

  /**
   * Build prompt for command parsing
   */
  private buildParsingPrompt(input: string, context: ExperimentContext): string {
    const contextInfo = context.experiment 
      ? `Current experiment has ${context.experiment.blocks?.length || 0} blocks.`
      : 'No experiment loaded.';

    return `Parse this natural language command for a psychology experiment design tool:

Command: "${input}"

Context: ${contextInfo}
${context.selectedElement ? `Currently selected: ${context.selectedElement.type} (${context.selectedElement.id})` : ''}

Parse the command and return a JSON object with:
{
  "intent": "one of: add_stimulus, add_trial, add_block, modify_timing, add_condition, add_response, configure_experiment, add_instruction, set_parameter, generate_factorial, add_randomization, add_break, validate_design, explain_concept, suggest_improvement",
  "parameters": {
    // Relevant parameters extracted from the command
  },
  "confidence": 0.0-1.0
}

Examples:
- "Add a red fixation cross for 500ms" -> {"intent": "add_stimulus", "parameters": {"type": "cross", "color": "red", "duration": 500}, "confidence": 0.95}
- "Create 20 Stroop trials" -> {"intent": "add_trial", "parameters": {"count": 20, "type": "stroop"}, "confidence": 0.9}`;
  }

  /**
   * Build prompt for experiment suggestions
   */
  private buildSuggestionPrompt(experiment: any): string {
    return `Analyze this psychology experiment and suggest improvements:

${JSON.stringify(experiment, null, 2)}

Provide suggestions as a JSON array of objects with:
{
  "type": "performance|design|accessibility|timing|validation",
  "title": "Brief title",
  "description": "Detailed description",
  "code": "Optional ForgeScript code to implement",
  "priority": "low|medium|high",
  "rationale": "Why this improvement matters"
}

Focus on:
1. Timing precision and accuracy
2. Counterbalancing and randomization
3. Data quality and validity
4. Participant experience
5. Reproducibility`;
  }

  /**
   * Fallback parsing for when AI fails
   */
  private fallbackParsing(input: string, context: ExperimentContext): DesignCommand {
    const lower = input.toLowerCase();
    let intent: DesignIntent = 'explain_concept';
    let parameters: Record<string, any> = {};
    let confidence = 0.3;

    // Simple keyword matching
    if (lower.includes('add') && lower.includes('stimulus')) {
      intent = 'add_stimulus';
      confidence = 0.7;
    } else if (lower.includes('add') && lower.includes('trial')) {
      intent = 'add_trial';
      confidence = 0.7;

      // Extract number if present
      const match = input.match(/(\d+)\s*trial/i);
      if (match) {
        parameters.count = parseInt(match[1]);
        confidence = 0.8;
      }
    } else if (lower.includes('time') || lower.includes('duration')) {
      intent = 'modify_timing';
      confidence = 0.6;
    } else if (lower.includes('factorial')) {
      intent = 'generate_factorial';
      confidence = 0.8;
    }

    return {
      intent,
      parameters,
      confidence,
      originalInput: input,
      context
    };
  }

  /**
   * Get static suggestions for autocomplete
   */
  private getStaticSuggestions(partial: string): string[] {
    const suggestions = [
      'Add a fixation cross',
      'Add a text stimulus',
      'Add an image stimulus',
      'Create a trial',
      'Create a block of trials',
      'Set inter-trial interval',
      'Add keyboard response',
      'Add instructions',
      'Generate factorial design',
      'Add practice trials'
    ];

    return suggestions
      .filter(s => s.toLowerCase().includes(partial.toLowerCase()))
      .slice(0, 5);
  }
}

