/**
 * @psyforge/headless - Pre-built cognitive models for experiment simulation
 */

import type {
  CognitiveModel,
  SimpleRTModel,
  StroopModel,
  NBackModel,
  VisualSearchModel
} from './types';

/**
 * Simple reaction time model with practice and fatigue effects
 */
export class SimpleRTCognitiveModel implements SimpleRTModel {
  baseRT: number = 400;
  practiceEffect: number = 0.02;
  fatigueEffect: number = 0.001;
  errorRate: number = 0.05;
  rtVariability: number = 0.15;

  constructor(config?: Partial<SimpleRTModel>) {
    if (config) {
      Object.assign(this, config);
    }
  }

  reactionTime(stimulus: any, difficulty: number): number {
    // Base RT with difficulty modifier
    let rt = this.baseRT * (1 + difficulty * 0.5);

    // Add variability using ex-Gaussian distribution
    rt += this.exGaussian(rt * this.rtVariability);

    return Math.max(150, rt); // Minimum 150ms
  }

  accuracy(stimulus: any, fatigue: number): boolean {
    // Error rate increases with fatigue
    const errorProb = this.errorRate * (1 + fatigue * 2);
    return Math.random() > errorProb;
  }

  learningCurve(trialNumber: number, condition: string): number {
    // Exponential learning curve
    return 1 - this.practiceEffect * (1 - Math.exp(-trialNumber / 20));
  }

  private exGaussian(sigma: number): number {
    // Simplified ex-Gaussian approximation
    const gaussian = this.gaussian() * sigma;
    const exponential = -Math.log(Math.random()) * sigma * 0.5;
    return gaussian + exponential;
  }

  private gaussian(): number {
    // Box-Muller transform
    const u1 = Math.random();
    const u2 = Math.random();
    return Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
  }
}

/**
 * Stroop task model with interference and conflict adaptation
 */
export class StroopCognitiveModel implements StroopModel {
  congruentRT: number = 350;
  incongruentRT: number = 450;
  interferenceDecay: number = 0.1;
  speedAccuracyTradeoff: number = 0.3;
  conflictAdaptation: number = 0.05;
  private previousConflict: boolean = false;

  constructor(config?: Partial<StroopModel>) {
    if (config) {
      Object.assign(this, config);
    }
  }

  reactionTime(stimulus: any, difficulty: number): number {
    const isCongruent = stimulus.condition === 'congruent';
    let baseRT = isCongruent ? this.congruentRT : this.incongruentRT;

    // Conflict adaptation effect (Gratton effect)
    if (!isCongruent && this.previousConflict) {
      baseRT *= (1 - this.conflictAdaptation);
    }

    this.previousConflict = !isCongruent;

    // Add variability
    const variability = baseRT * 0.12;
    baseRT += (Math.random() - 0.5) * variability * 2;

    return Math.max(200, baseRT);
  }

  accuracy(stimulus: any, fatigue: number): boolean {
    const isCongruent = stimulus.condition === 'congruent';

    // Base accuracy
    let accuracy = isCongruent ? 0.98 : 0.92;

    // Fatigue reduces accuracy more for incongruent trials
    if (!isCongruent) {
      accuracy -= fatigue * 0.15;
    } else {
      accuracy -= fatigue * 0.05;
    }

    // Speed-accuracy tradeoff
    accuracy *= (1 - this.speedAccuracyTradeoff * 0.1);

    return Math.random() < accuracy;
  }

  learningCurve(trialNumber: number, condition: string): number {
    // Stroop interference reduces with practice
    if (condition === 'incongruent') {
      return 1 - this.interferenceDecay * (1 - Math.exp(-trialNumber / 50));
    }
    return 0.98; // Minimal learning for congruent trials
  }
}

/**
 * N-Back working memory task model
 */
export class NBackCognitiveModel implements NBackModel {
  baseRT: number = 500;
  loadEffect: number = 0.15;
  hitRate: number = 0.85;
  falseAlarmRate: number = 0.15;
  workingMemoryCapacity: number = 7;
  private memoryBuffer: any[] = [];

  constructor(config?: Partial<NBackModel>) {
    if (config) {
      Object.assign(this, config);
    }
  }

  reactionTime(stimulus: any, difficulty: number): number {
    const nBack = stimulus.nBack || 2;

    // RT increases with n-back level
    let rt = this.baseRT * (1 + this.loadEffect * nBack);

    // Add cognitive load effect
    const cognitiveLoad = Math.min(1, nBack / this.workingMemoryCapacity);
    rt *= (1 + cognitiveLoad * 0.3);

    // Add variability
    rt += (Math.random() - 0.5) * rt * 0.2;

    return Math.max(300, rt);
  }

  accuracy(stimulus: any, fatigue: number): boolean {
    const nBack = stimulus.nBack || 2;
    const isTarget = stimulus.isTarget || false;

    // Update memory buffer
    this.memoryBuffer.push(stimulus);
    if (this.memoryBuffer.length > this.workingMemoryCapacity) {
      this.memoryBuffer.shift();
    }

    // Calculate accuracy based on signal detection theory
    let hitProb = this.hitRate;
    let faProb = this.falseAlarmRate;

    // Reduce accuracy with higher n-back levels
    const loadPenalty = Math.min(0.3, nBack * 0.05);
    hitProb -= loadPenalty;
    faProb += loadPenalty * 0.5;

    // Fatigue effect
    hitProb -= fatigue * 0.2;
    faProb += fatigue * 0.1;

    if (isTarget) {
      return Math.random() < hitProb;
    } else {
      return Math.random() > faProb;
    }
  }

  learningCurve(trialNumber: number, condition: string): number {
    // Working memory tasks show limited practice effects
    return 1 - 0.05 * (1 - Math.exp(-trialNumber / 100));
  }
}

/**
 * Visual search task model
 */
export class VisualSearchCognitiveModel implements VisualSearchModel {
  targetPresentRT: number = 600;
  targetAbsentRT: number = 900;
  setSizeSlope: number = 25;
  popoutEffect: number = 0.5;
  distractorSimilarity: number = 0.5;

  constructor(config?: Partial<VisualSearchModel>) {
    if (config) {
      Object.assign(this, config);
    }
  }

  reactionTime(stimulus: any, difficulty: number): number {
    const setSize = stimulus.setSize || 8;
    const targetPresent = stimulus.targetPresent || false;
    const isPopout = stimulus.popout || false;

    // Base RT depends on target presence
    let rt = targetPresent ? this.targetPresentRT : this.targetAbsentRT;

    // Set size effect (linear for serial search)
    if (isPopout) {
      // Popout search is parallel (flat slope)
      rt += this.setSizeSlope * this.popoutEffect * Math.log(setSize);
    } else {
      // Serial search has linear slope
      rt += this.setSizeSlope * setSize;

      // Target absent requires exhaustive search
      if (!targetPresent) {
        rt *= 1.5;
      }
    }

    // Distractor similarity effect
    rt *= (1 + this.distractorSimilarity * 0.3);

    // Add variability
    rt += (Math.random() - 0.5) * rt * 0.15;

    return Math.max(250, rt);
  }

  accuracy(stimulus: any, fatigue: number): boolean {
    const setSize = stimulus.setSize || 8;
    const targetPresent = stimulus.targetPresent || false;

    // Base accuracy
    let accuracy = 0.95;

    // Reduce accuracy with set size
    accuracy -= Math.min(0.2, setSize * 0.01);

    // Fatigue effect is stronger for larger set sizes
    accuracy -= fatigue * 0.1 * (1 + setSize / 20);

    // False alarms are more likely with high distractor similarity
    if (!targetPresent) {
      accuracy -= this.distractorSimilarity * 0.1;
    }

    return Math.random() < accuracy;
  }

  learningCurve(trialNumber: number, condition: string): number {
    // Visual search shows moderate practice effects
    return 1 - 0.1 * (1 - Math.exp(-trialNumber / 40));
  }
}

/**
 * Factory for creating cognitive models
 */
export class CognitiveModelFactory {
  static createSimpleRT(config?: Partial<SimpleRTModel>): CognitiveModel {
    return new SimpleRTCognitiveModel(config);
  }

  static createStroop(config?: Partial<StroopModel>): CognitiveModel {
    return new StroopCognitiveModel(config);
  }

  static createNBack(config?: Partial<NBackModel>): CognitiveModel {
    return new NBackCognitiveModel(config);
  }

  static createVisualSearch(config?: Partial<VisualSearchModel>): CognitiveModel {
    return new VisualSearchCognitiveModel(config);
  }
}

/**
 * Pre-configured cognitive models for common paradigms
 */
export const CognitiveModels = {
  simpleRT: new SimpleRTCognitiveModel(),

  stroopModel: new StroopCognitiveModel(),

  nBackModel: new NBackCognitiveModel(),

  visualSearchModel: new VisualSearchCognitiveModel(),

  // Variations with different parameters
  fastSimpleRT: new SimpleRTCognitiveModel({ baseRT: 250, rtVariability: 0.1 }),

  strongStroopInterference: new StroopCognitiveModel({ 
    incongruentRT: 550, 
    interferenceDecay: 0.05 
  }),

  highLoadNBack: new NBackCognitiveModel({ 
    workingMemoryCapacity: 5,
    loadEffect: 0.25 
  }),

  difficultVisualSearch: new VisualSearchCognitiveModel({
    setSizeSlope: 40,
    distractorSimilarity: 0.8
  })
};

