/**
 * @psyforge/headless - Virtual device implementations for hardware simulation
 */

import type {
  VirtualDevice,
  VirtualKeyboard,
  VirtualMouse,
  VirtualEyeTracker,
  VirtualEEG
} from './types';

/**
 * Base virtual device implementation
 */
abstract class BaseVirtualDevice implements VirtualDevice {
  type: 'keyboard' | 'mouse' | 'eyetracker' | 'eeg';
  latency: number;
  precision: number;
  noiseLevel: number;

  constructor(
    type: VirtualDevice['type'],
    latency: number = 5,
    precision: number = 1,
    noiseLevel: number = 0.05
  ) {
    this.type = type;
    this.latency = latency;
    this.precision = precision;
    this.noiseLevel = noiseLevel;
  }

  /**
   * Add noise to a measurement
   */
  protected addNoise(value: number): number {
    const noise = (Math.random() - 0.5) * 2 * this.noiseLevel;
    return value * (1 + noise);
  }

  /**
   * Simulate device latency
   */
  protected simulateLatency(): number {
    // Latency follows gamma distribution
    const shape = 2; // Shape parameter
    const scale = this.latency / shape; // Scale to achieve mean = latency

    let sum = 0;
    for (let i = 0; i < shape; i++) {
      sum += -Math.log(Math.random()) * scale;
    }

    return Math.max(0, sum);
  }
}

/**
 * Virtual keyboard device
 */
export class VirtualKeyboardDevice extends BaseVirtualDevice implements VirtualKeyboard {
  keyPressVariability: number;
  keyReleaseVariability: number;
  doublePressThreshold: number;
  private keyStates: Map<string, boolean> = new Map();
  private lastKeyPress: Map<string, number> = new Map();

  constructor(config?: Partial<VirtualKeyboard>) {
    super('keyboard', config?.latency || 5, config?.precision || 1, config?.noiseLevel || 0.02);
    this.keyPressVariability = config?.keyPressVariability || 10;
    this.keyReleaseVariability = config?.keyReleaseVariability || 15;
    this.doublePressThreshold = config?.doublePressThreshold || 50;
  }

  /**
   * Simulate key press event
   */
  simulateKeyPress(key: string, timestamp: number): { key: string; timestamp: number; latency: number } {
    const latency = this.simulateLatency();
    const variability = this.addNoise(this.keyPressVariability);

    // Check for double press
    const lastPress = this.lastKeyPress.get(key) || 0;
    if (timestamp - lastPress < this.doublePressThreshold) {
      // Ignore double press
      return { key: '', timestamp: 0, latency: 0 };
    }

    this.keyStates.set(key, true);
    this.lastKeyPress.set(key, timestamp);

    return {
      key,
      timestamp: timestamp + latency + variability,
      latency: latency + variability
    };
  }

  /**
   * Simulate key release event
   */
  simulateKeyRelease(key: string, timestamp: number): { key: string; timestamp: number; duration: number } {
    const latency = this.simulateLatency();
    const variability = this.addNoise(this.keyReleaseVariability);
    const pressTime = this.lastKeyPress.get(key) || timestamp;

    this.keyStates.set(key, false);

    return {
      key,
      timestamp: timestamp + latency + variability,
      duration: timestamp - pressTime
    };
  }

  /**
   * Get current key states
   */
  getKeyStates(): Map<string, boolean> {
    return new Map(this.keyStates);
  }
}

/**
 * Virtual mouse device
 */
export class VirtualMouseDevice extends BaseVirtualDevice implements VirtualMouse {
  movementNoise: number;
  clickVariability: number;
  scrollSensitivity: number;
  private position: { x: number; y: number } = { x: 0, y: 0 };
  private buttonStates: Map<number, boolean> = new Map();

  constructor(config?: Partial<VirtualMouse>) {
    super('mouse', config?.latency || 3, config?.precision || 2, config?.noiseLevel || 0.03);
    this.movementNoise = config?.movementNoise || 2;
    this.clickVariability = config?.clickVariability || 5;
    this.scrollSensitivity = config?.scrollSensitivity || 3;
  }

  /**
   * Simulate mouse movement
   */
  simulateMovement(targetX: number, targetY: number, duration: number): Array<{ x: number; y: number; timestamp: number }> {
    const steps = Math.ceil(duration / 16.67); // 60 FPS
    const path: Array<{ x: number; y: number; timestamp: number }> = [];

    const startX = this.position.x;
    const startY = this.position.y;

