/**
 * Code generator for ForgeScript from AI commands
 */

import type { DesignCommand } from './types.js';
import { COMMAND_PROMPTS, FORGESRIPT_EXAMPLES } from './prompts.js';

/**
 * Generates ForgeScript code from parsed commands
 */
export class CodeGenerator {
  /**
   * Generate code from a design command
   */
  async generateFromCommand(command: DesignCommand): Promise<string> {
    switch (command.intent) {
      case 'add_stimulus':
        return this.generateStimulus(command.parameters);

      case 'add_trial':
        return this.generateTrial(command.parameters);

      case 'add_block':
        return this.generateBlock(command.parameters);

      case 'modify_timing':
        return this.generateTimingModification(command.parameters);

      case 'add_condition':
        return this.generateCondition(command.parameters);

      case 'add_response':
        return this.generateResponse(command.parameters);

      case 'add_instruction':
        return this.generateInstruction(command.parameters);

      case 'generate_factorial':
        return this.generateFactorial(command.parameters);

      case 'add_randomization':
        return this.generateRandomization(command.parameters);

      case 'add_break':
        return this.generateBreak(command.parameters);

      default:
        throw new Error(`Code generation not implemented for intent: ${command.intent}`);
    }
  }

  /**
   * Generate stimulus code
   */
  private generateStimulus(params: Record<string, any>): string {
    const { type = 'text', content = 'X', duration = 1000, color, fontSize, position } = params;

    let code = `experiment()\n  .trial('stimulus_trial')\n`;

    switch (type) {
      case 'text':
      case 'word':
        code += `    .stimulus('text_stim', '${content}')\n`;
        if (fontSize) code += `      .fontSize(${fontSize})\n`;
        if (color) code += `      .color('${color}')\n`;
        break;

      case 'cross':
      case 'fixation':
        code += `    .stimulus('fixation', '+')\n`;
        code += `      .fontSize(${fontSize || 24})\n`;
        if (color) code += `      .color('${color}')\n`;
        break;

      case 'image':
        code += `    .stimulus('image_stim', '${content}')\n`;
        code += `      .size(${params.width || 200}, ${params.height || 200})\n`;
        break;

      case 'shape':
        const shape = params.shape || 'circle';
        code += `    .shape('shape_stim', '${shape}')\n`;
        if (params.size) code += `      .size(${params.size})\n`;
        if (color) code += `      .color('${color}')\n`;
        break;
    }

    if (position) {
      code += `      .position(${position.x || 0}, ${position.y || 0})\n`;
    }

    code += `      .duration(${duration});`;

    return code;
  }

